#include <iostream>
#include <iomanip>
#include <cmath>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    double x;
    int n;
    cin >> x >> n;

    double sum = 0.0;
    double term = x;
    for (int i = 0; i < n; ++i) {
        term = sin(term);
        sum += term;
    }

    cout << fixed << setprecision(3) << sum << '\n';
    return 0;
}
